# Create a monthly actual-cost export
export_body = {
    "properties": {
        "schedule": {
            "status": "Active",
            "recurrence": "Monthly",
            "recurrencePeriod": {
                "from": "2024-01-01T00:00:00Z",
                "to": "2025-12-31T00:00:00Z"
            }
        },
        "format": "Csv",
        "deliveryInfo": {
            "destination": {
                "resourceId": "/subscriptions/<sub>/resourceGroups/<rg>/providers/Microsoft.Storage/storageAccounts/<sa>",
                "container": "cost-exports",
                "rootFolderPath": f"billing-profile/{billing_profile_name}"
            }
        },
        "definition": {
            "type": "ActualCost",
            "timeframe": "TheLastMonth",
            "dataSet": {
                "granularity": "Daily",
                "configuration": {
                    "columns": [
                        "Date","SubscriptionId","ResourceGroup","ResourceLocation",
                        "MeterCategory","MeterName","Quantity","UnitPrice","CostInBillingCurrency",
                        "Tags","InvoiceSectionName","BillingProfileName"
                    ]
                }
            }
        }
    }
}

create_url = list_url + "/monthly-actual-cost"
resp = requests.put(create_url, headers=headers, json=export_body)
print(resp.status_code, resp.json().get("name"))

import requests
from azure.identity import DefaultAzureCredential

credential = DefaultAzureCredential()
token = credential.get_token("https://management.azure.com/.default").token
headers = {"Authorization": f"Bearer {token}", "Content-Type": "application/json"}

billing_account_name = "1234567"
scope = f"/providers/Microsoft.Billing/billingAccounts/{billing_account_name}"

budget_body = {
    "properties": {
        "category": "Cost",
        "amount": 50000,
        "timeGrain": "Monthly",
        "timePeriod": {
            "startDate": "2024-01-01",
            "endDate": "2024-12-31"
        },
        "notifications": {
            "Actual_GreaterThan_80_Percent": {
                "enabled": True,
                "operator": "GreaterThan",
                "threshold": 80,
                "contactEmails": [
                    "finance-team@contoso.com",
                    "cloud-ops@contoso.com"
                ],
                "thresholdType": "Actual"
            },
            "Forecasted_GreaterThan_100_Percent": {
                "enabled": True,
                "operator": "GreaterThan",
                "threshold": 100,
                "contactEmails": ["finance-lead@contoso.com"],
                "thresholdType": "Forecasted"
            }
        },
        "filter": {}
    }
}

url = (
    f"https://management.azure.com{scope}/"
    f"providers/Microsoft.Consumption/budgets/monthly-ea-budget"
    f"?api-version=2023-11-01"
)
resp = requests.put(url, headers=headers, json=budget_body)
print(resp.status_code, resp.json().get("name"))
